const fs = require('fs');
const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
        AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
        VerticalAlign, UnderlineType, LevelFormat, PageBreak, Header, Footer, PageNumber } = require('docx');

// Table border style
const tableBorder = { style: BorderStyle.SINGLE, size: 1, color: "999999" };
const cellBorders = { top: tableBorder, bottom: tableBorder, left: tableBorder, right: tableBorder };
const headerBorders = { top: tableBorder, bottom: tableBorder, left: tableBorder, right: tableBorder };

// Helper function to create a table row
function createRow(cells, isHeader = false) {
  return new TableRow({
    tableHeader: isHeader,
    children: cells.map((cellText, index) => {
      const isFirstColumn = index === 0;
      return new TableCell({
        borders: cellBorders,
        width: { size: isFirstColumn ? 2000 : 3500, type: WidthType.DXA },
        shading: isHeader ? { fill: "E8F4F8", type: ShadingType.CLEAR } : undefined,
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({
          alignment: isFirstColumn ? AlignmentType.LEFT : AlignmentType.LEFT,
          spacing: { before: 50, after: 50 },
          children: [new TextRun({ text: cellText, bold: isHeader, size: isHeader ? 22 : 20 })]
        })]
      });
    })
  });
}

// Helper function to create a three-column table row
function createThreeColRow(cells, isHeader = false, colWidths = [2000, 3500, 2500]) {
  return new TableRow({
    tableHeader: isHeader,
    children: cells.map((cellText, index) => {
      return new TableCell({
        borders: cellBorders,
        width: { size: colWidths[index], type: WidthType.DXA },
        shading: isHeader ? { fill: "E8F4F8", type: ShadingType.CLEAR } : undefined,
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({
          alignment: index === 0 ? AlignmentType.LEFT : AlignmentType.CENTER,
          spacing: { before: 50, after: 50 },
          children: [new TextRun({ text: cellText, bold: isHeader, size: isHeader ? 22 : 20 })]
        })]
      });
    })
  });
}

// Helper function for complex table
function createDetailRow(items, colWidths) {
  return new TableRow({
    children: items.map((item, index) => {
      const isHeader = index === 0;
      return new TableCell({
        borders: cellBorders,
        width: { size: colWidths[index], type: WidthType.DXA },
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({
          alignment: AlignmentType.LEFT,
          spacing: { before: 50, after: 50 },
          children: [new TextRun({ text: item, size: 20, bold: isHeader })]
        })]
      });
    })
  });
}

const doc = new Document({
  styles: {
    default: {
      document: {
        run: { font: "Microsoft YaHei", size: 22 }
      }
    },
    paragraphStyles: [
      {
        id: "Title",
        name: "Title",
        basedOn: "Normal",
        run: { size: 40, bold: true, color: "2C3E50", font: "Microsoft YaHei" },
        paragraph: { spacing: { before: 200, after: 200 }, alignment: AlignmentType.CENTER }
      },
      {
        id: "Heading1",
        name: "Heading 1",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 32, bold: true, color: "2980B9", font: "Microsoft YaHei" },
        paragraph: { spacing: { before: 240, after: 120 }, outlineLevel: 0 }
      },
      {
        id: "Heading2",
        name: "Heading 2",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 28, bold: true, color: "34495E", font: "Microsoft YaHei" },
        paragraph: { spacing: { before: 180, after: 100 }, outlineLevel: 1 }
      },
      {
        id: "Heading3",
        name: "Heading 3",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 24, bold: true, color: "7F8C8D", font: "Microsoft YaHei" },
        paragraph: { spacing: { before: 140, after: 80 }, outlineLevel: 2 }
      }
    ]
  },
  numbering: {
    config: [
      {
        reference: "check-list",
        levels: [
          {
            level: 0,
            format: LevelFormat.BULLET,
            text: "✓",
            alignment: AlignmentType.LEFT,
            style: { paragraph: { indent: { left: 720, hanging: 360 } } }
          }
        ]
      },
      {
        reference: "cross-list",
        levels: [
          {
            level: 0,
            format: LevelFormat.BULLET,
            text: "✗",
            alignment: AlignmentType.LEFT,
            style: { paragraph: { indent: { left: 720, hanging: 360 } } }
          }
        ]
      }
    ]
  },
  sections: [{
    properties: {
      page: {
        margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 }
      }
    },
    headers: {
      default: new Header({
        children: [
          new Paragraph({
            alignment: AlignmentType.RIGHT,
            children: [new TextRun({ text: "APP产品报价单", size: 20, color: "7F8C8D" })]
          })
        ]
      })
    },
    footers: {
      default: new Footer({
        children: [
          new Paragraph({
            alignment: AlignmentType.CENTER,
            children: [
              new TextRun({ text: "第 ", size: 20 }),
              new TextRun({ children: [PageNumber.CURRENT] }),
              new TextRun({ text: " 页", size: 20 })
            ]
          })
        ]
      })
    },
    children: [
      // Title
      new Paragraph({
        heading: HeadingLevel.TITLE,
        children: [new TextRun("智能打印扫描工具APP")]
      }),
      new Paragraph({
        heading: HeadingLevel.TITLE,
        children: [new TextRun("产品报价单")]
      }),
      new Paragraph({
        alignment: AlignmentType.CENTER,
        spacing: { after: 300 },
        children: [new TextRun({ text: "（人天单价：¥2,000）", size: 22, color: "7F8C8D" })]
      }),

      // Section 1: 项目基本信息
      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        children: [new TextRun("一、项目基本信息")]
      }),
      new Table({
        columnWidths: [2000, 7000],
        margins: { top: 100, bottom: 100, left: 100, right: 100 },
        rows: [
          createRow(["项目名称", "智能打印扫描工具APP"]),
          createRow(["APP类型", "打印扫描/效率工具类应用"]),
          createRow(["开发平台", "iOS + Android 双平台"]),
          createRow(["功能版本", "专业版（10大核心功能）"]),
          createRow(["报价日期", "2026年3月24日"])
        ]
      }),

      // Section 2: 核心功能模块
      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        spacing: { before: 300 },
        children: [new TextRun("二、核心功能模块（10大功能）")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [new TextRun("📄 打印功能模块（5项）")]
      }),
      new Table({
        columnWidths: [1800, 7200],
        margins: { top: 100, bottom: 100, left: 100, right: 100 },
        rows: [
          createRow(["文档打印", "支持PDF、Word、Excel、PPT等文档格式打印；支持云文档导入；打印预览；页面缩放、黑白/彩色选择；份数设置"]),
          createRow(["图片打印", "支持JPG、PNG、HEIC等图片格式；单张/批量打印；图片裁剪、旋转、滤镜效果；证件照排版打印；照片尺寸自定义"]),
          createRow(["网页打印", "内置浏览器；支持长截图打印；网页内容智能识别；广告过滤；打印区域自定义选择"]),
          createRow(["模版打印", "内置丰富打印模版（发票、合同、简历、证书等）；模版在线编辑；自定义模版上传保存；企业模版库"]),
          createRow(["文身打印", "图片自定义编辑；文字添加效果；图案缩放旋转；镜像翻转打印；贴纸打印支持"])
        ]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        spacing: { before: 200 },
        children: [new TextRun("📷 扫描功能模块（2项）")]
      }),
