const fs = require('fs');
const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
        AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
        VerticalAlign, LevelFormat, Header, Footer, PageNumber, PageBreak } = require('docx');

// Table border style
const tableBorder = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const cellBorders = { top: tableBorder, bottom: tableBorder, left: tableBorder, right: tableBorder };

// Helper function to create table row
function createRow(cells, isHeader = false) {
  return new TableRow({
    tableHeader: isHeader,
    children: cells.map((cellText, index) => {
      const isFirst = index === 0;
      return new TableCell({
        borders: cellBorders,
        width: { size: isFirst ? 2500 : 6500, type: WidthType.DXA },
        shading: isHeader ? { fill: "E8F4F8", type: ShadingType.CLEAR } : undefined,
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({
          alignment: AlignmentType.LEFT,
          spacing: { before: 80, after: 80 },
          children: [new TextRun({ text: cellText, bold: isHeader, size: 22 })]
        })]
      });
    })
  });
}

function createThreeColRow(cells, isHeader = false) {
  return new TableRow({
    tableHeader: isHeader,
    children: cells.map((cellText, index) => {
      return new TableCell({
        borders: cellBorders,
        width: { size: 3000, type: WidthType.DXA },
        shading: isHeader ? { fill: "E8F4F8", type: ShadingType.CLEAR } : undefined,
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { before: 80, after: 80 },
          children: [new TextRun({ text: cellText, bold: isHeader, size: 22 })]
        })]
      });
    })
  });
}

function createFourColRow(cells, isHeader = false, widths = [2000, 2500, 2500, 2500]) {
  return new TableRow({
    tableHeader: isHeader,
    children: cells.map((cellText, index) => {
      return new TableCell({
        borders: cellBorders,
        width: { size: widths[index], type: WidthType.DXA },
        shading: isHeader ? { fill: "E8F4F8", type: ShadingType.CLEAR } : undefined,
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({
          alignment: index === 0 ? AlignmentType.LEFT : AlignmentType.CENTER,
          spacing: { before: 80, after: 80 },
          children: [new TextRun({ text: cellText, bold: isHeader, size: 22 })]
        })]
      });
    })
  });
}

